export default function CustomerStories() {
  return (
    <div className="min-h-screen bg-navy-50 py-20 px-4 sm:px-6 lg:px-8">
      <div className="max-w-7xl mx-auto">
        <h1 className="text-4xl font-bold text-navy-900 text-center mb-8">Customer Stories</h1>
        <p className="text-lg text-navy-700 text-center max-w-3xl mx-auto">
          Read about how we've helped businesses achieve their goals.
        </p>
      </div>
    </div>
  );
}

export default function LifeAtClicknovation() {
  return (
    <div className="min-h-screen bg-navy-50 py-20 px-4 sm:px-6 lg:px-8">
      <div className="max-w-7xl mx-auto">
        <h1 className="text-4xl font-bold text-navy-900 text-center mb-8">Life at Clicknovation</h1>
        <p className="text-lg text-navy-700 text-center max-w-3xl mx-auto">
          Discover what it's like to work with us and be part of our innovative culture.
        </p>
      </div>
    </div>
  );
}

'use client';

import { motion } from 'framer-motion';

export default function FinalCTASection() {
  return (
    <section className="py-20 px-4 sm:px-6 lg:px-8 bg-gradient-to-r from-blue-600 to-blue-700 text-white">
      <div className="max-w-4xl mx-auto text-center">
        <motion.h2
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
          viewport={{ once: true }}
          className="text-3xl sm:text-4xl font-bold mb-6"
          style={{color: 'var(--heading-color, #FFFFFF)'}}
        >
          Let's Build the <span style={{color: '#FFFFFF'}}>Future</span> Together
        </motion.h2>
        <motion.p
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, delay: 0.2 }}
          viewport={{ once: true }}
          className="text-xl mb-8 leading-relaxed"
        >
          Your business deserves technology that works smarter, scales faster, and delivers results.
        </motion.p>
        <motion.p
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, delay: 0.4 }}
          viewport={{ once: true }}
          className="text-lg mb-12 text-blue-100 leading-relaxed"
        >
          Partner with us to transform your ideas into powerful digital solutions.
        </motion.p>
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, delay: 0.6 }}
          viewport={{ once: true }}
          className="flex flex-col sm:flex-row gap-4 justify-center"
        >
          <button className="bg-white text-blue-900 px-8 py-3 rounded-full font-semibold hover:bg-blue-100 transition-colors">
            Contact Us
          </button>
          <button className="border-2 border-white text-white px-8 py-3 rounded-full font-semibold hover:bg-white hover:text-blue-900 transition-colors">
            Get a Free Consultation
          </button>
        </motion.div>
      </div>
    </section>
  );
}

'use client';

import { motion } from 'framer-motion';

const testimonials = [
  {
    quote: 'Exceptional service and outstanding technical expertise. Their solutions helped us streamline operations and improve efficiency significantly.',
    author: 'Business Owner',
  },
  {
    quote: 'The team understood our vision perfectly and delivered beyond expectations. Highly professional and reliable.',
    author: 'Project Manager',
  },
  {
    quote: 'Their innovative approach and continuous support have made them a valuable technology partner for our business.',
    author: 'CEO',
  },
];

export default function TestimonialsSection() {
  return (
    <section className="py-20 px-4 sm:px-6 lg:px-8 bg-blue-900">
      <div className="max-w-7xl mx-auto">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
          viewport={{ once: true }}
          className="text-center mb-16"
        >
          <h2 className="text-3xl sm:text-4xl font-bold mb-4" style={{color: 'var(--heading-color, #FFFFFF)'}}>
            <span style={{color: '#FFFFFF'}}>Client</span> Testimonials
          </h2>
          <p className="text-xl text-blue-300 max-w-2xl mx-auto font-semibold">
            Trusted by Businesses. Proven by Results.
          </p>
        </motion.div>

        <div className="grid md:grid-cols-3 gap-8">
          {testimonials.map((testimonial, index) => (
            <motion.div
              key={index}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.8, delay: index * 0.2 }}
              viewport={{ once: true }}
              className="bg-blue-800 p-6 rounded-lg shadow-lg border border-blue-700"
            >
              <div className="text-blue-400 text-4xl mb-4">"</div>
              <p className="text-blue-100 mb-4 italic leading-relaxed">
                {testimonial.quote}
              </p>
              <p className="text-blue-300 font-semibold">
                — {testimonial.author}
              </p>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
}
